import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./Notes.css";

export default function Notes() {
  const navigate = useNavigate();
  const [notes, setNotes] = useState([]);
  const [userRole, setUserRole] = useState("");

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("myNotes")) || [];
    setNotes(saved);

    // Fetch current user role from localStorage
    const currentUser = JSON.parse(localStorage.getItem("loggedInUser"));
    if (currentUser && currentUser.role) {
      setUserRole(currentUser.role);
    }
  }, []);

  function saveNote(e) {
    e.preventDefault();
    const title = e.target.title.value.trim();
    const content = e.target.content.value.trim();

    if (!title || !content) {
      alert("Please fill in both fields.");
      return;
    }

    const newNote = { title, content, sharedBy: userRole };
    const updatedNotes = [newNote, ...notes];
    setNotes(updatedNotes);
    localStorage.setItem("myNotes", JSON.stringify(updatedNotes));

    e.target.title.value = "";
    e.target.content.value = "";
  }

  return (
    <div className="notes-container">
      <h1>📒 Student Notes</h1>

      {/* Only allow Students to upload notes */}
      {userRole === "student" ? (
        <form onSubmit={saveNote}>
          <label>Title</label>
          <input name="title" placeholder="Title" />

          <label>Content</label>
          <textarea name="content" placeholder="Write your note here..." />

          <button type="submit">Upload Note</button>
        </form>
      ) : (
        <p className="note-hint">Only students can upload notes. You can still view all shared notes below.</p>
      )}

      {notes.length === 0 ? (
        <p>No notes uploaded yet.</p>
      ) : (
        notes.map((n, i) => (
          <div key={i} className="note">
            <h3>{n.title}</h3>
            <p>{n.content}</p>
            {n.sharedBy && (
              <small>
                <i>Shared by: {n.sharedBy}</i>
              </small>
            )}
          </div>
        ))
      )}

      <h2>📚 Study Resources to Learn and Revise</h2>

      <div className="resources">
        <div className="resource">
          <img src="https://www.w3schools.com/images/w3schools_green.jpg" alt="W3Schools" />
          <h4>🌐 W3Schools</h4>
          <p>Learn HTML, CSS, JavaScript, and more with simple tutorials.</p>
          <a href="https://www.w3schools.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/GeeksforGeeks.svg/1200px-GeeksforGeeks.svg.png" alt="GeeksforGeeks" />
          <h4>📚 GeeksforGeeks</h4>
          <p>Master programming concepts, algorithms, and coding questions.</p>
          <a href="https://www.geeksforgeeks.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://tse4.mm.bing.net/th/id/OIP.LcXrTu6oqBs7kHzk_BeuCgAAAA?pid=Api&P=0&h=180" alt="freeCodeCamp" />
          <h4>⚡ freeCodeCamp</h4>
          <p>Learn coding by building projects with free full-length courses.</p>
          <a href="https://www.freecodecamp.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://cdn-1.webcatalog.io/catalog/mdn-web-docs/mdn-web-docs-icon-filled-256.webp?v=1714775085873" alt="MDN Web Docs" />
          <h4>📖 MDN Web Docs</h4>
          <p>The best official docs for web technologies like HTML, CSS, JS.</p>
          <a href="https://developer.mozilla.org/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://cdn-1.webcatalog.io/catalog/javatpoint/javatpoint-icon-unplated.png?v=1714777503504" alt="JavaTpoint" />
          <h4>📗 JavaTpoint</h4>
          <p>Simple explanations for Java, Python, C, C++, Web Dev topics.</p>
          <a href="https://www.javatpoint.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>

        <div className="resource">
          <img src="https://images.crunchbase.com/image/upload/c_pad,h_256,w_256,f_auto,q_auto:eco,dpr_1/jjp8px3g1vtfyyutzbtj" alt="Programiz" />
          <h4>📘 Programiz</h4>
          <p>Easy tutorials and examples for Python, C, C++, Java beginners.</p>
          <a href="https://www.programiz.com/" target="_blank" rel="noreferrer">Visit</a>
        </div>
      </div>

      <p>
        <button className="back-btn" onClick={() => navigate("/dashboard")}>⇐ Back to Dashboard</button>
      </p>
    </div>
  );
}
